  ('diplomatic-9e854390-moex-00356', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '關於立法院職權之敘述，下列何者正確？', '["依憲法本文規定由監察院行使之人事同意權，依據憲法增修條文之規定，已改由立法院行使", "立法院對於各機關所編列預算之數額，得在款項目節間移動增減並追加或削減原預算之項目", "依據憲法本文之規定，立法院遇有立法委員五分之一以上之請求，得開臨時會", "依憲法增修條文之規定，立法院對總統之罷免案，須經全體立法委員至少二分之一以上之提議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00357', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '臺灣地區人民小明小時候到大陸地區求學，並長期居住在大陸地區，小明於今年5月3日滿20歲時 向大陸地區申辦了中華人民共和國護照，根據臺灣地區與大陸地區人民關係條例，下列對小明可能受 到的影響，何者錯誤？', '["小明無法參加年底臺灣地區縣市長的投票", "小明無法參加臺灣地區公務人員考試", "小明無法擔任民意代表", "小明仍擁有臺灣戶籍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00358', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '大陸地區人民大瑤嫁給臺灣地區人民小明，大瑤在臺灣設有戶籍已經滿10年但未滿20年，根據臺灣 地區與大陸地區人民關係條例，大瑤「不可以」從事以下那個工作？', '["國防大學教職人員，非涉及國家安全或機密科技研究之職務", "私立大學教職人員，非涉及國家安全或機密科技研究之職務", "國立大學教職人員，非涉及國家安全或機密科技研究之職務", "民意代表"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00359', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '下列對於中國大陸政黨與政治體制的描述何者錯誤？', '["維持中國共產黨一黨專政", "中國共產黨領導下的多黨執政與政治協商制度", "人民民主專政", "民主集中制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00360', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '中國大陸提出過許多對臺統戰的指導方針，其中針對臺灣社會，中國大陸曾提出「一代一線」，下列 對「一代一線」的描述何者錯誤？', '["中國大陸政協主席俞正聲在2017年3月全國政協會議開幕時提出「一代一線」", "「一代一線」是指青年一代與基層一線", "目前中國大陸已經以「三中一青」取代「一代一線」作為對臺統戰指導方針", "是針對臺灣「一代一線」，給予「接近中國大陸民眾的各種待遇」，也就是所謂的「居民待遇」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00361', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '「一國兩制」是鄧小平於 1982 年 1 月會見美國華人協會主席李耀茲時首次提出的，下列對「一國兩 制」的描述何者錯誤？', '["臺灣特別行政區可以「完全自治」，實行同中國大陸不同的制度", "臺灣的司法可以獨立，終審權不需到北京", "臺灣可以擁有自己的軍隊，但不能對中國大陸構成威脅", "臺灣的黨政軍系統都由臺灣自己管，中國大陸不派人去臺"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00362', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '美國在雷根政府時期曾提出過對臺灣「六項保證」，下列何者不是「六項保證」的內容？', '["美國對臺軍售不事先與中國諮商", "美國不扮演兩岸調解人的角色", "美國不承認中國對臺灣的主權主張", "美國不承認一個中國政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00363', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '「海峽兩岸經濟合作架構協議」（ECFA）是兩岸所簽署的雙邊經貿協議，下列對「海峽兩岸經濟合作 架構協議」的描述何者錯誤？', '["兩岸於2010年第五次江陳會談中共同簽署", "ECFA採取「早期收穫」方式，對雙方最急迫且獲有共識的貨品與服務業，優先進行關稅減免與市 場開放", "ECFA因為「太陽花學運」關係，目前已經終止", "雙方依照約定的稅率調降關稅，臺灣方面提出了539項早收清單，中國大陸方面則提出了267項早 收清單"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00364', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '陳水扁總統任內曾提出只要中共無意對臺灣動武，則保證「四不一沒有」，下列何者不是此主張內容？', '["不會推動改變現狀的統獨議題公投", "不更改國號", "不推動兩國論入憲", "沒有九二共識的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
